UPDATE public.questions SET
  stimulus_text = 'The text argues that how people engage with digital tools falls into two groups. One group uses technology for defined goals—the writers label this "task-focused" use. The other group uses technology mainly for enjoyment or leisure, which they call "leisure-focused" use. This split matters because it clarifies why individuals adopt technology differently and how those patterns shape daily life. The writers maintain that distinguishing task-focused from leisure-focused use is essential for explaining twenty-first-century technology habits.',
